CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $BODY$
BEGIN
    NEW.updated_at = CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$BODY$ LANGUAGE plpgsql;

changeSet.rollback:
DROP TRIGGER IF EXISTS update_persons_updated_at ON persons;
DROP TRIGGER IF EXISTS update_agreements_updated_at ON agreements;
DROP TRIGGER IF EXISTS update_promo_codes_updated_at ON promo_codes;
DROP TRIGGER IF EXISTS update_countries_updated_at ON countries;
DROP TRIGGER IF EXISTS update_discounts_updated_at ON discounts;
DROP TRIGGER IF EXISTS update_payments_updated_at ON payments;

changeSet.sql:
CREATE OR REPLACE FUNCTION validate_promo_code(
    p_code VARCHAR,
    p_agreement_date DATE,
    p_premium_amount DECIMAL
)
RETURNS TABLE(is_valid BOOLEAN, error_message TEXT, discount_amount DECIMAL) AS $BODY$
DECLARE
    v_promo promo_codes%ROWTYPE;
    v_discount DECIMAL;
BEGIN
    SELECT * INTO v_promo
    FROM promo_codes
    WHERE code = p_code
      AND is_active = TRUE
      AND valid_from <= p_agreement_date
      AND valid_to >= p_agreement_date;

    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'Promo code not found or expired', 0::DECIMAL;
        RETURN;
    END IF;

    IF v_promo.max_usage_count IS NOT NULL
       AND v_promo.current_usage_count >= v_promo.max_usage_count THEN
        RETURN QUERY SELECT FALSE, 'Promo code usage limit reached', 0::DECIMAL;
        RETURN;
    END IF;

    IF v_promo.min_premium_amount IS NOT NULL
       AND p_premium_amount < v_promo.min_premium_amount THEN
        RETURN QUERY SELECT FALSE, 'Premium amount too low for this promo code', 0::DECIMAL;
        RETURN;
    END IF;

    IF v_promo.discount_type = 'PERCENTAGE' THEN
        v_discount := p_premium_amount * v_promo.discount_value / 100;
    ELSE
        v_discount := v_promo.discount_value;
    END IF;

    IF v_promo.max_discount_amount IS NOT NULL
       AND v_discount > v_promo.max_discount_amount THEN
        v_discount := v_promo.max_discount_amount;
    END IF;

    RETURN QUERY SELECT TRUE, NULL::TEXT, v_discount;
END;
$BODY$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION validate_promo_code_for_update(
    p_code VARCHAR,
    p_agreement_date DATE,
    p_premium_amount DECIMAL
)
RETURNS TABLE(
    is_valid         BOOLEAN,
    error_message    TEXT,
    discount_amount  DECIMAL,
    promo_code_id    BIGINT
) AS $BODY$
DECLARE
    v_promo promo_codes%ROWTYPE;
    v_discount DECIMAL;
BEGIN
    -- SELECT FOR UPDATE: блокируем строку до конца транзакции.
    -- Конкурентный вызов будет ждать здесь, пока текущая транзакция
    -- не завершится (COMMIT или ROLLBACK).
    SELECT * INTO v_promo
    FROM promo_codes
    WHERE code = p_code
      AND is_active = TRUE
      AND valid_from <= p_agreement_date
      AND valid_to >= p_agreement_date
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'Promo code not found or expired', 0::DECIMAL, NULL::BIGINT;
        RETURN;
    END IF;

    -- Проверка лимита использований.
    -- current_usage_count здесь гарантированно актуален: строка заблокирована,
    -- поэтому никакая параллельная транзакция не могла его изменить.
    IF v_promo.max_usage_count IS NOT NULL
       AND v_promo.current_usage_count >= v_promo.max_usage_count THEN
        RETURN QUERY SELECT FALSE, 'Promo code usage limit reached', 0::DECIMAL, v_promo.id;
        RETURN;
    END IF;

    IF v_promo.min_premium_amount IS NOT NULL
       AND p_premium_amount < v_promo.min_premium_amount THEN
        RETURN QUERY SELECT FALSE, 'Premium amount too low for this promo code', 0::DECIMAL, v_promo.id;
        RETURN;
    END IF;

    IF v_promo.discount_type = 'PERCENTAGE' THEN
        v_discount := p_premium_amount * v_promo.discount_value / 100;
    ELSE
        v_discount := v_promo.discount_value;
    END IF;

    IF v_promo.max_discount_amount IS NOT NULL
       AND v_discount > v_promo.max_discount_amount THEN
        v_discount := v_promo.max_discount_amount;
    END IF;

    RETURN QUERY SELECT TRUE, NULL::TEXT, v_discount, v_promo.id;
END;
$BODY$ LANGUAGE plpgsql;
